<p style="text-align: justify;">En 1936 se mudaría a Barrio Obrero, donde construirán el Estadio Adriano Irala y más adelante el General Pablo Rojas, actual estadio del equipo azulgrana, que fue remodelado por última vez en la pasada década y fue reinaugurado en 2017.</p>
<p style="text-align: justify;">El Ciclón de Barrio Obrero, se convirtió en uno de los fenómenos sociales más convocantes de nuestro país. Además, logró 34 títulos de Liga y 5 copas nacionales a lo largo de 111 años de historia.</p>","ticketsUrl":null,"storeUrl":null,"bets":null,"isClickable":true},"awayTeam":{"id":"ffc746b2-fa9b-4174-b79a-c6175824d1a5","teamMaster":null,"name":"Club Rubio Ñú","shortName":"Rubio Ñú","nickname":"Rubio Ñú","displayName":"RUB","image":{"id":"50494945-e75f-4f99-9fe8-1fee1790c3d9","alt":null,"url":"https://statics-maker.llt-services.com/apf/images/2026/01/13/original/a3f8e92f-7faa-48b8-a27e-c0fb55104eee-876.png","height":500,"width":500,"identifierProcessed":"a3f8e92f-7faa-48b8-a27e-c0fb55104eee-876","isImageProcessed":true,"thumbnails":{"xsmall":"https://statics-maker.llt-services.com/apf/images/2026/01/13/xsmall/a3f8e92f-7faa-48b8-a27e-c0fb55104eee-876.png","xlarge":"https://statics-maker.llt-services.com/apf/images/2026/01/13/xlarge/a3f8e92f-7faa-48b8-a27e-c0fb55104eee-876.png"}},"shield":null,"streakGame":null,"ownTeam":true,"slug":"rubio-nu-266","webPageUrl":null,"facebookUrl":null,"twitterUrl":null,"instagramUrl":null,"colorAccent":null,"palette":null,"about":null,"ticketsUrl":null,"storeUrl":null,"bets":null,"isClickable":true},"homeScore":2,"awayScore":0,"homeShootOutScore":null,"awayShootOutScore":null,"period":{"id":"bc375750-de27-4c2c-923f-232df74d4140","name":"Partido finalizado","shortName":"FT","type":"FullTime"},"gameTime":94,"enabledLayout":true,"date":"2026-05-24","time":"2026-05-24T20:00:00Z","ticketing":null}],"campaign":null},{"id":"26923935-e005-44e9-9a87-3365a130f30e","type":"gap","config":{"spacing":"32px"}},{"id":"22eb9438-d157-473a-96f0-be9a9a9cec51","type":"football_competition_standings","subtype":"standings_full","info":{"title":null,"button":{"url":null,"name":null,"page":null,"type":"neutral","source":"none","target":null,"position":"top"}},"config":{"design":"reduced","showLegend":true,"color_style":"defaul