08","image":null,"isClickable":true},"ranking":{"value":1016,"ranking":2}},{"id":"c30c6224-2848-4622-acc7-7483d6e45904","team":{"id":"7fd7d89e-9550-4fd3-88cb-92dbd4eca817","teamMaster":null,"name":"Club Cerro Porteño","shortName":"Cerro Porteño","nickname":"Cerro Porteño","displayName":"CCP","image":{"id":"50dcc632-8d15-45b9-8dc8-ce36b569493e","alt":null,"url":"https://statics-maker.llt-services.com/apf/images/2025/06/04/original/50f0da33-cae8-4d6d-8ed3-bb11f1934b72-977.png","height":258,"width":240,"identifierProcessed":"50f0da33-cae8-4d6d-8ed3-bb11f1934b72-977","isImageProcessed":true,"thumbnails":{"xsmall":"https://statics-maker.llt-services.com/apf/images/2025/06/04/xsmall/50f0da33-cae8-4d6d-8ed3-bb11f1934b72-977.png","xlarge":"https://statics-maker.llt-services.com/apf/images/2025/06/04/xlarge/50f0da33-cae8-4d6d-8ed3-bb11f1934b72-977.png"}},"shield":null,"streakGame":null,"ownTeam":true,"slug":"cerro-porteno-221","webPageUrl":null,"facebookUrl":null,"twitterUrl":null,"instagramUrl":null,"colorAccent":"#0033a0","palette":{"10":"#E6E9FA","20":"#B8C3ED","30":"#8A9DDE","40":"#5C79CC","50":"#2E55B8","60":"#0033a0","70":"#002586","80":"#001967","90":"#000F45","100":"#00051E"},"about":"<p style="text-align: justify;">Fundado el 1 de Octubre de 1912 por Susana Núñez y un grupo de jóvenes entusiastas, con el fin de promover la práctica del fútbol y la unidad entre paraguayos, por eso tomaron el nombre de la Batalla de Cerro Porteño, clave para el nacimiento de la patria y los colores azul y rojo, que representaban a los partidos tradicionales, por aquel entonces enemistados. </p>
<p style="text-align: justify;">En 1936 se mudaría a Barrio Obrero, donde construirán el Estadio Adriano Irala y más adelante el General Pablo Rojas, actual estadio del equipo azulgrana, que fue remodelado por última vez en la pasada década y fue reinaugurado en 2017.</p>
<p style="text-align: justify;">El Ciclón de Barrio Obrero, se convirtió en uno de los fenómenos sociales más convocantes de nuestro país. Además, logró 34 títulos de Liga y 5 copas nacionales a lo largo de 111 años de historia.</p>","ticketsUrl":null,"storeUrl":null,"bets":null,"isClickable":true},"player":{"id":"25b68f4b-3e7d-479f-918e-af25af4f4b7c","playerMaster":null,"name":"Matías Pérez","nickname":"Matías Pérez","preferredFoot":null,"imageMainUrl":null,"slug":"matias-perez-7707","image":null,"isClickable":true},"ranking":{"value":995,"ranking":3}},{"id":"a075ab8e-c251-4069-9506-c0f4fa34dcc5","team":{"id":"f0f42369-0c41-40ad-88a3-62c2b0e71b93","teamMaster":null,"name":"Club Nacional Asunción","shortName":"Nacional Asunción","nickname":"Nacional","displayName":"CNA","image":{"id":"65b589cc-022d-441d-a4c9-ef42f0165e39","alt":null,"url":"https://statics-maker.llt-services.com/apf/images/2024/06/13/original/c4de65af-19b2-4e73-926a-b4392eb519c0-981.png","height":800,"width":800,"identifierProcessed":"c4de65af-19b2-4e73-926a-b4392eb519c0-981","thumbnails":{"xsmall":"https://statics-maker.llt-services.com/apf/images/2024/06/13/xsmall/c4de65af-19b2-4e73-926a-b4392eb519c0-981.png","xlarge":"https://statics-maker.llt-services.com/apf/images/2024/06/13/xlarge/c4de65af-19b2-4e73-926a-b4392eb519c0-981.png"}},"shield":null,"streakGame":null,"ownTeam":true,"slug":"nacional-260","webPageUrl":null,"facebookUrl":null,"twitterUrl":null,"instagramUrl":null,"colorAccent":null,"palette":null,"about":null,"ticketsUrl":null,"storeUrl":null,"bets":null,"isClickable":true},"player":{"id":"5eaef4ab-5a53-4cbc-b103-83fb941f7406","playerMaster":null,"name":"Alexis Cañete","nickname":"Alexis Cañete","preferredFoot":null,"imageMainUrl":null,"slug":"alexis-canete-126336","image":null,"isClickable":true},"ranking":{"value":990,"ranking":4}},{"id":"9b094bd6-8132-457f-8779-7fcf3329cf4f","team":{"id":"08dd91da-e1cb-4a2a-87c8-c41fedbff124","teamMaster":null,"name":"Sportivo Ameliano","shortName":"S